function createBaseSsmlDocumentationRequest(): SsmlDocumentationRequest {
  return { voiceId: "", locale: "" };
}

export const SsmlDocumentationRequest: MessageFns<SsmlDocumentationRequest> = {
  encode(message: SsmlDocumentationRequest, writer: BinaryWriter = new BinaryWriter()): BinaryWriter {
    if (message.voiceId !== "") {
      writer.uint32(10).string(message.voiceId);
    }
    if (message.locale !== "") {
      writer.uint32(18).string(message.locale);
    }
    return writer;
  },

  decode(input: BinaryReader | Uint8Array, length?: number): SsmlDocumentationRequest {
    const reader = input instanceof BinaryReader ? input : new BinaryReader(input);
    const end = length === undefined ? reader.len : reader.pos + length;
    const message = createBaseSsmlDocumentationRequest();
    while (reader.pos < end) {
      const tag = reader.uint32();
      switch (tag >>> 3) {
        case 1: {
          if (tag !== 10) {
            break;
          }

          message.voiceId = reader.string();
          continue;
        }
        case 2: {
          if (tag !== 18) {
            break;
          }

          message.locale = reader.string();
          continue;
        }
      }
      if ((tag & 7) === 4 || tag === 0) {
        break;
      }
      reader.skip(tag & 7);
    }
    return message;
  },

  fromJSON(object: any): SsmlDocumentationRequest {
    return {
      voiceId: isSet(object.voiceId) ? globalThis.String(object.voiceId) : "",
      locale: isSet(object.locale) ? globalThis.String(object.locale) : "",
    };
  },

  toJSON(message: SsmlDocumentationRequest): unknown {
    const obj: any = {};
    if (message.voiceId !== "") {
      obj.voiceId = message.voiceId;
    }
    if (message.locale !== "") {
      obj.locale = message.locale;
    }
    return obj;
  },

  create<I extends Exact<DeepPartial<SsmlDocumentationRequest>, I>>(base?: I): SsmlDocumentationRequest {
    return SsmlDocumentationRequest.fromPartial(base ?? ({} as any));
  },
  fromPartial<I extends Exact<DeepPartial<SsmlDocumentationRequest>, I>>(object: I): SsmlDocumentationRequest {
    const message = createBaseSsmlDocumentationRequest();
    message.voiceId = object.voiceId ?? "";
    message.locale = object.locale ?? "";
    return message;
  },
};

function createBaseSsmlDocumentationResponse(): SsmlDocumentationResponse {
  return { voiceId: "", documentation: [] };
}

export const SsmlDocumentationResponse: MessageFns<SsmlDocumentationResponse> = {
  encode(message: SsmlDocumentationResponse, writer: BinaryWriter = new BinaryWriter()): BinaryWriter {
    if (message.voiceId !== "") {
      writer.uint32(10).string(message.voiceId);
    }
    for (const v of message.documentation) {
      SsmlDocSection.encode(v!, writer.uint32(18).fork()).join();
    }
    return writer;
  },

  decode(input: BinaryReader | Uint8Array, length?: number): SsmlDocumentationResponse {
    const reader = input instanceof BinaryReader ? input : new BinaryReader(input);
    const end = length === undefined ? reader.len : reader.pos + length;
    const message = createBaseSsmlDocumentationResponse();
    while (reader.pos < end) {
      const tag = reader.uint32();
      switch (tag >>> 3) {
        case 1: {
          if (tag !== 10) {
            break;
          }

          message.voiceId = reader.string();
          continue;
        }
        case 2: {
          if (tag !== 18) {
            break;
          }

          message.documentation.push(SsmlDocSection.decode(reader, reader.uint32()));
          continue;
        }
      }
      if ((tag & 7) === 4 || tag === 0) {
        break;
      }
      reader.skip(tag & 7);
    }
    return message;
  },

  fromJSON(object: any): SsmlDocumentationResponse {
    return {
      voiceId: isSet(object.voiceId) ? globalThis.String(object.voiceId) : "",
      documentation: globalThis.Array.isArray(object?.documentation)
        ? object.documentation.map((e: any) => SsmlDocSection.fromJSON(e))
        : [],
    };
  },

  toJSON(message: SsmlDocumentationResponse): unknown {
    const obj: any = {};
    if (message.voiceId !== "") {
      obj.voiceId = message.voiceId;
    }
    if (message.documentation?.length) {
      obj.documentation = message.documentation.map((e) => SsmlDocSection.toJSON(e));
    }
    return obj;
  },

  create<I extends Exact<DeepPartial<SsmlDocumentationResponse>, I>>(base?: I): SsmlDocumentationResponse {
    return SsmlDocumentationResponse.fromPartial(base ?? ({} as any));
  },
  fromPartial<I extends Exact<DeepPartial<SsmlDocumentationResponse>, I>>(object: I): SsmlDocumentationResponse {
    const message = createBaseSsmlDocumentationResponse();
    message.voiceId = object.voiceId ?? "";
    message.documentation = object.documentation?.map((e) => SsmlDocSection.fromPartial(e)) || [];
    return message;
  },
};

